1	package claude
2	
3	import (
4		"context"
5		"fmt"
6		"math"
7		"time"
8	
9		"github.com/easel/fizeau/internal/harnesses"
10		"github.com/easel/fizeau/internal/harnesses/ptyquota"
11		"github.com/easel/fizeau/internal/pty/cassette"
12		"github.com/easel/fizeau/internal/pty/session"
13	)
14	
15	type quotaPTYOptions struct {
16		binary      string
17		args        []string
18		workdir     string
19		env         []string
20		cassetteDir string
21	}
22	
23	type QuotaPTYOption func(*quotaPTYOptions)
24	
25	func WithQuotaPTYCommand(binary string, args ...string) QuotaPTYOption {
26		return func(opts *quotaPTYOptions) {
27			opts.binary = binary
28			opts.args = append([]string(nil), args...)
29		}
30	}
31	
32	func WithQuotaPTYWorkdir(workdir string) QuotaPTYOption {
33		return func(opts *quotaPTYOptions) {
34			opts.workdir = workdir
35		}
36	}
37	
38	func WithQuotaPTYEnv(env ...string) QuotaPTYOption {
39		return func(opts *quotaPTYOptions) {
40			opts.env = append([]string(nil), env...)
41		}
42	}
43	
44	func WithQuotaPTYCassetteDir(dir string) QuotaPTYOption {
45		return func(opts *quotaPTYOptions) {
46			opts.cassetteDir = dir
47		}
48	}
49	
50	func ReadClaudeQuotaViaPTY(timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
51		windows, account, _, err := captureClaudeQuotaViaPTY(context.Background(), timeout, opts...)
52		return windows, account, err
53	}
54	
55	func RefreshClaudeQuotaViaPTY(timeout time.Duration, opts ...QuotaPTYOption) (ClaudeQuotaSnapshot, error) {
56		windows, account, _, err := captureClaudeQuotaViaPTY(context.Background(), timeout, opts...)
57		if err != nil {
58			return ClaudeQuotaSnapshot{}, err
59		}
60		return claudeQuotaSnapshotFromWindows(windows, account), nil
61	}
62	
63	func ReadClaudeQuotaFromCassette(dir string) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
64		reader, err := cassette.Open(dir)
65		if err != nil {
66			return nil, nil, err
67		}
68		text := reader.Final().FinalText
69		if text == "" {
70			frames := reader.Frames()
71			if len(frames) > 0 {
72				text = stringsJoinLines(frames[len(frames)-1].Text)
73			}
74		}
75		windows, account := parseClaudeUsageOutput(text)
76		if len(windows) == 0 {
77			return nil, account, fmt.Errorf("no quota windows found in claude quota cassette")
78		}
79		if err := validateClaudeQuotaEvidence(windows, account); err != nil {
80			return nil, account, fmt.Errorf("incomplete claude quota cassette: %w", err)
81		}
82		return windows, account, nil
83	}
84	
85	func captureClaudeQuotaViaPTY(ctx context.Context, timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, ptyquota.Result, error) {
86		cfg := quotaPTYOptions{binary: "claude"}
87		for _, opt := range opts {
88			if opt != nil {
89				opt(&cfg)
90			}
91		}
92		var windows []harnesses.QuotaWindow
93		var account *harnesses.AccountInfo
94		result, err := ptyquota.Run(ctx, ptyquota.Config{
95			HarnessName:  "claude",
96			Binary:       cfg.binary,
97			Args:         cfg.args,
98			Workdir:      cfg.workdir,
99			Env:          cfg.env,
100			Command:      "/usage\r",
101			ReadyMarkers: []string{"❯", "> "},
102			DoneWhen:     claudeUsageComplete,
103			Timeout:      timeout,
104			Size:         session.Size{Rows: 50, Cols: 220},
105			CassetteDir:  cfg.cassetteDir,
106			Quota: func(text string) (cassette.QuotaRecord, error) {
107				windows, account = parseClaudeUsageOutput(text)
108				if len(windows) == 0 {
109					return cassette.QuotaRecord{}, fmt.Errorf("no quota windows found in claude /usage output")
110				}
111				if err := validateClaudeQuotaEvidence(windows, account); err != nil {
112					return cassette.QuotaRecord{}, fmt.Errorf("incomplete claude /usage output: %w", err)
113				}
114				return quotaRecord(windows, map[string]any{"plan_type": accountPlan(account)}), nil
115			},
116		})
117		if err != nil {
118			return nil, nil, result, err
119		}
120		if len(windows) == 0 {
121			windows, account = parseClaudeUsageOutput(result.Text)
122		}
123		if len(windows) == 0 {
124			return nil, account, result, fmt.Errorf("no quota windows found in claude /usage output")
125		}
126		if err := validateClaudeQuotaEvidence(windows, account); err != nil {
127			return nil, account, result, fmt.Errorf("incomplete claude /usage output: %w", err)
128		}
129		return windows, account, result, nil
130	}
131	
132	func claudeQuotaSnapshotFromWindows(windows []harnesses.QuotaWindow, account *harnesses.AccountInfo) ClaudeQuotaSnapshot {
133		fiveHourUsed := usedPercentFor(windows, "session")
134		weeklyUsed := usedPercentFor(windows, "weekly-all")
135		if weeklyUsed < 0 {
136			weeklyUsed = usedPercentFor(windows, "weekly-sonnet")
137		}
138		return ClaudeQuotaSnapshot{
139			CapturedAt:        time.Now().UTC(),
140			FiveHourLimit:     100,
141			FiveHourRemaining: remainingPercent(fiveHourUsed),
142			WeeklyLimit:       100,
143			WeeklyRemaining:   remainingPercent(weeklyUsed),
144			Windows:           append([]harnesses.QuotaWindow(nil), windows...),
145			Source:            "pty",
146			Account:           account,
147		}
148	}
149	
150	func usedPercentFor(windows []harnesses.QuotaWindow, limitID string) float64 {
151		for _, window := range windows {
152			if window.LimitID == limitID {
153				return window.UsedPercent
154			}
155		}
156		return -1
157	}
158	
159	func hasQuotaWindow(windows []harnesses.QuotaWindow, limitID string) bool {
160		return usedPercentFor(windows, limitID) >= 0
161	}
162	
163	func claudeUsageComplete(text string) bool {
164		windows, _ := parseClaudeUsageOutput(text)
165		return hasQuotaWindow(windows, "session") && (hasQuotaWindow(windows, "weekly-all") || hasQuotaWindow(windows, "weekly-sonnet"))
166	}
167	
168	func validateClaudeQuotaEvidence(windows []harnesses.QuotaWindow, account *harnesses.AccountInfo) error {
169		if accountPlan(account) == "" {
170			return fmt.Errorf("missing account plan")
171		}
172		if !hasQuotaWindow(windows, "session") {
173			return fmt.Errorf("missing session window")
174		}
175		if !hasQuotaWindow(windows, "weekly-all") && !hasQuotaWindow(windows, "weekly-sonnet") {
176			return fmt.Errorf("missing weekly window")
177		}
178		return nil
179	}
180	
181	func remainingPercent(used float64) int {
182		if used < 0 {
183			return 0
184		}
185		remaining := int(math.Round(100 - used))
186		if remaining < 0 {
187			return 0
188		}
189		if remaining > 100 {
190			return 100
191		}
192		return remaining
193	}
194	
195	func quotaRecord(windows []harnesses.QuotaWindow, metadata map[string]any) cassette.QuotaRecord {
196		records := make([]map[string]any, 0, len(windows))
197		for _, window := range windows {
198			records = append(records, map[string]any{
199				"name":           window.Name,
200				"limit_id":       window.LimitID,
201				"window_minutes": window.WindowMinutes,
202				"used_percent":   window.UsedPercent,
203				"resets_at":      window.ResetsAt,
204				"state":          window.State,
205			})
206		}
207		accountClass, _ := metadata["plan_type"].(string)
208		return cassette.QuotaRecord{
209			Source:            "pty",
210			Status:            string(ptyquota.StatusOK),
211			CapturedAt:        time.Now().UTC().Format(time.RFC3339),
212			FreshnessWindow:   DefaultClaudeQuotaStaleAfter.String(),
213			StalenessBehavior: "stale quota evidence keeps Claude out of automatic routing and is treated as limited",
214			AccountClass:      accountClass,
215			Windows:           records,
216			Metadata:          metadata,
217		}
218	}
219	
220	func accountPlan(account *harnesses.AccountInfo) string {
221		if account == nil {
222			return ""
223		}
224		return account.PlanType
225	}
226	
227	func stringsJoinLines(lines []string) string {
228		out := ""
229		for i, line := range lines {
230			if i > 0 {
231				out += "\n"
232			}
233			out += line
234		}
235		return out
236	}
