1	package claude
2	
3	import (
4		"context"
5		"fmt"
6		"os/exec"
7		"regexp"
8		"strings"
9		"time"
10	
11		"github.com/easel/fizeau/internal/harnesses"
12		"github.com/easel/fizeau/internal/harnesses/ptyquota"
13		"github.com/easel/fizeau/internal/pty/cassette"
14		"github.com/easel/fizeau/internal/pty/session"
15	)
16	
17	const ClaudeModelDiscoveryFreshnessWindow = 24 * time.Hour
18	
19	var (
20		claudeFullModelPattern         = regexp.MustCompile(`\bclaude-[a-z0-9][a-z0-9._-]*\b`)
21		claudeFullFamilyVersionPattern = regexp.MustCompile(`\bclaude-(sonnet|opus|haiku)-([0-9]+)[.-]([0-9]{1,2})(?:\b|-)`)
22		claudeFamilyVersionPattern     = regexp.MustCompile(`\b(?:claude\s+)?(sonnet|opus|haiku)\s+([0-9]+(?:[.-][0-9]+){0,2})\b`)
23		claudeAliasPattern             = regexp.MustCompile(`(?m)(?:^|[\s'"])(sonnet|opus|haiku)(?:$|[\s'"])`)
24		claudeEffortPattern            = regexp.MustCompile(`--effort\s+<level>.*\(([^)]*)\)`)
25	)
