38	func ReadClaudeModelDiscoveryViaPTY(timeout time.Duration, opts ...QuotaPTYOption) (harnesses.ModelDiscoverySnapshot, error) {
39		cfg := quotaPTYOptions{binary: "claude"}
40		for _, opt := range opts {
41			if opt != nil {
42				opt(&cfg)
43			}
44		}
45		var snapshot harnesses.ModelDiscoverySnapshot
46		_, err := ptyquota.Run(context.Background(), ptyquota.Config{
47			HarnessName:  "claude",
48			Binary:       cfg.binary,
49			Args:         cfg.args,
50			Workdir:      cfg.workdir,
51			Env:          cfg.env,
52			Command:      "/model\r",
53			ReadyMarkers: []string{"❯", "> "},
54			DoneWhen:     claudeModelDiscoveryComplete,
55			Timeout:      timeout,
56			Size:         session.Size{Rows: 50, Cols: 220},
57			CassetteDir:  cfg.cassetteDir,
58			Discovery: func(text string) (cassette.DiscoveryRecord, error) {
59				snapshot = claudeDiscoveryFromText(text, "pty")
60				if len(snapshot.Models) == 0 {
61					return cassette.DiscoveryRecord{}, fmt.Errorf("no models found in claude /model output")
62				}
63				return discoveryRecord(snapshot), nil
64			},
65		})
66		if err != nil {
67			return harnesses.ModelDiscoverySnapshot{}, err
68		}
69		if len(snapshot.Models) == 0 {
70			return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("no models found in claude /model output")
71		}
72		return snapshot, nil
73	}
