75	func ReadClaudeModelDiscoveryFromCassette(dir string) (harnesses.ModelDiscoverySnapshot, error) {
76		reader, err := cassette.Open(dir)
77		if err != nil {
78			return harnesses.ModelDiscoverySnapshot{}, err
79		}
80		if rec := reader.Discovery(); rec != nil && len(rec.Models) > 0 {
81			return snapshotFromDiscoveryRecord(*rec), nil
82		}
83		text := reader.Final().FinalText
84		if text == "" {
85			frames := reader.Frames()
86			if len(frames) > 0 {
87				text = strings.Join(frames[len(frames)-1].Text, "\n")
88			}
89		}
90		snapshot := claudeDiscoveryFromText(text, "cassette")
91		if len(snapshot.Models) == 0 {
92			return harnesses.ModelDiscoverySnapshot{}, fmt.Errorf("no models found in claude model cassette")
93		}
94		return snapshot, nil
95	}
