248	func discoveryRecord(snapshot harnesses.ModelDiscoverySnapshot) cassette.DiscoveryRecord {
249		return cassette.DiscoveryRecord{
250			Source:            snapshot.Source,
251			Status:            string(ptyquota.StatusOK),
252			Models:            append([]string(nil), snapshot.Models...),
253			ReasoningLevels:   append([]string(nil), snapshot.ReasoningLevels...),
254			CapturedAt:        snapshot.CapturedAt.UTC().Format(time.RFC3339),
255			FreshnessWindow:   snapshot.FreshnessWindow,
256			StalenessBehavior: "stale model discovery evidence requires authenticated PTY refresh before capability promotion",
257			Metadata:          map[string]any{"detail": snapshot.Detail},
