19	// Fallback only: unpinned runs resolve through model discovery first.
20	const fallbackDefaultModel = "claude-sonnet-4-6"
21	
22	// Default size for the per-Execute event channel buffer. Large enough that
23	// fast tool-call bursts (claude can emit dozens of blocks per turn) do not
24	// stall the parser, small enough to bound memory in pathological streams.
25	const defaultEventBuffer = 64
26	
27	// Default idle/stream timeout when ExecuteRequest leaves IdleTimeout unset.
28	// Mirrors the wall-clock cap the DDx-side runner used historically; an
29	// explicit ExecuteRequest.Timeout still wins.
30	const defaultIdleTimeout = 0 // 0 = no idle cap; rely on Timeout / ctx.
