13	// claudeQuotaFreshness is the constant freshness window for claude quota
14	// evidence. Mirrors DefaultClaudeQuotaStaleAfter (kept as a separate name
15	// so the CONTRACT-004 method has a stable, contract-named constant).
16	const claudeQuotaFreshness = DefaultClaudeQuotaStaleAfter
17	
