28	// Store is the per-process in-memory state for runtime signal collection.
29	// It holds per-provider latency windows and the most recently observed
30	// rate-limit header signals. All methods are safe for concurrent use.
31	type Store struct {
32		mu        sync.RWMutex
33		latencies map[string]*LatencyWindow
34		headers   *headerStore
35	}
36	
37	// CollectInput describes the provider identity needed to assemble a runtime
38	// signal. Type controls the collection path; BaseURL is used by local
39	// providers for the live /v1/models check.
40	type CollectInput struct {
41		Type    string
42		BaseURL string
43	}
44	
45	// NewStore creates an empty Store ready for use.
46	func NewStore() *Store {
47		return &Store{
48			latencies: make(map[string]*LatencyWindow),
49			headers:   newHeaderStore(),
50		}
51	}
52	
53	// DefaultStore is the process-singleton Store used by the package-level
54	// RecordResponse and Collect functions.
55	var DefaultStore = NewStore()
56	
57	// RecordResponse records an HTTP response observation for a provider using the
58	// DefaultStore. providerType controls which header parser is applied
59	// ("openrouter", "anthropic", or any other value for the OpenAI parser).
60	func RecordResponse(provider string, h http.Header, latency time.Duration, providerType string) {
61		DefaultStore.RecordResponse(provider, h, latency, providerType)
62	}
63	
64	// RecordResponse records an HTTP response observation. It updates both the
65	// latency window and the header signal store for the named provider.
66	func (s *Store) RecordResponse(provider string, h http.Header, latency time.Duration, providerType string) {
67		win := s.latencyWindow(provider)
68		win.Record(latency)
69	
70		if h != nil {
71			now := time.Now()
72			var sig quotaheaders.Signal
73			switch providerType {
74			case "openrouter":
75				sig = quotaheaders.ParseOpenRouter(h, now)
76			case "anthropic":
77				sig = quotaheaders.ParseAnthropic(h, now)
78			default:
79				sig = quotaheaders.ParseOpenAI(h, now)
80			}
81			s.headers.record(provider, sig)
82		}
83	}
84	
85	// Collect assembles a runtime Signal for the named provider using
86	// DefaultStore.
87	func Collect(ctx context.Context, providerName string, cfg CollectInput) (Signal, error) {
88		return DefaultStore.Collect(ctx, providerName, cfg)
89	}
90	
91	// Collect assembles a runtime Signal for providerName. The cfg.Type field
92	// controls which collection path is used:
93	//
94	//   - "claude"       → existing internal/harnesses/claude/quota_cache.go
95	//   - "codex"        → existing internal/harnesses/codex/quota_cache.go
96	//   - "gemini"       → existing internal/harnesses/gemini/quota_cache.go
97	//   - "openrouter"   → most recently recorded rate-limit headers (OpenRouter parser)
98	//   - "openai", "anthropic", and unknown HTTP types → rate-limit headers
99	//   - local types    → HTTP GET /v1/models alive check (no quota concept)
100	func (s *Store) Collect(ctx context.Context, providerName string, cfg CollectInput) (Signal, error) {
101		sig := Signal{
102			Provider:   providerName,
103			Status:     StatusUnknown,
104			RecordedAt: time.Now().UTC(),
105		}
106	
107		s.mu.RLock()
108		win := s.latencies[providerName]
109		s.mu.RUnlock()
110		if win != nil {
111			sig.RecentP50Latency = win.P50()
112		}
113	
114		providerType := cfg.Type
115	
116		switch providerType {
117		case "claude":
118			collectClaudeSignal(&sig)
119		case "codex":
120			collectCodexSignal(&sig)
121		case "gemini":
122			collectGeminiSignal(&sig)
123		case "ds4", "llama-server", "omlx", "lmstudio", "lucebox", "vllm", "rapid-mlx", "ollama":
124			collectLocalSignal(ctx, cfg.BaseURL, &sig)
125		default:
126			s.collectHeaderSignal(providerName, &sig)
127		}
128	
129		return sig, nil
130	}
