132	// CacheSource returns the discoverycache.Source descriptor for a provider's
133	// runtime signal. The file path resolves to runtime/<provider>.json.
134	func CacheSource(providerName string) discoverycache.Source {
135		return discoverycache.Source{
136			Tier:            "runtime",
137			Name:            providerName,
138			TTL:             RuntimeTTL,
139			RefreshDeadline: RuntimeRefreshDeadline,
140		}
141	}
142	
143	// Write serializes sig and stores it in M1's runtime cache tier. The cache
144	// file lands at <cache.Root>/runtime/<sig.Provider>.json.
145	func Write(cache *discoverycache.Cache, sig Signal) error {
146		data, err := json.Marshal(sig)
147		if err != nil {
148			return err
149		}
150		src := CacheSource(sig.Provider)
151		return cache.Refresh(src, func(_ context.Context) ([]byte, error) {
152			return data, nil
153		})
154	}
