211	func collectGeminiSignal(sig *Signal) {
212		r := &geminiharness.Runner{}
213		status, err := r.QuotaStatus(context.Background(), time.Now())
214		if err != nil {
215			return
216		}
217		switch status.State {
218		case harnesses.QuotaOK:
219			sig.Status = StatusAvailable
220		case harnesses.QuotaBlocked:
221			sig.Status = StatusExhausted
222			zero := 0
223			sig.QuotaRemaining = &zero
224			// QuotaUnavailable and QuotaStale both leave Status as StatusUnknown
225		}
226	}
