261	// collectLocalSignal performs an HTTP GET /v1/models alive check for local
262	// providers. Local providers have no quota concept; only StatusAvailable vs
263	// StatusDegraded is determined.
264	func collectLocalSignal(ctx context.Context, baseURL string, sig *Signal) {
265		if baseURL == "" {
266			return // StatusUnknown
267		}
268		timeoutCtx, cancel := context.WithTimeout(ctx, aliveCheckTimeout)
269		defer cancel()
270	
271		checkURL := baseURL + "/v1/models"
272		req, err := http.NewRequestWithContext(timeoutCtx, http.MethodGet, checkURL, nil) // #nosec G107
273		if err != nil {
274			return // StatusUnknown; bad URL
275		}
276		resp, err := (&http.Client{}).Do(req)
277		if err != nil {
278			sig.Status = StatusDegraded
279			sig.LastErrorMsg = err.Error()
280			now := time.Now().UTC()
281			sig.LastErrorAt = &now
282			return
283		}
284		defer resp.Body.Close()
285	
286		if resp.StatusCode >= 200 && resp.StatusCode < 300 {
287			sig.Status = StatusAvailable
288			now := time.Now().UTC()
289			sig.LastSuccessAt = &now
290		} else {
291			sig.Status = StatusDegraded
292		}
293	}
