}

// TestClaudeQuotaRoutingFromSnapshot tests the internal routing decision
// logic via claudeQuotaRoutingFromSnapshot and claudeQuotaStatusFromSnapshot.
func TestClaudeQuotaRoutingFromSnapshot(t *testing.T) {
	now := time.Date(2026, 4, 12, 12, 0, 0, 0, time.UTC)

	fresh := &claudeQuotaSnapshot{
		CapturedAt:        now.Add(-1 * time.Minute),
		FiveHourRemaining: 5000,
		FiveHourLimit:     10000,
		WeeklyRemaining:   50000,
		WeeklyLimit:       70000,
		Source:            "pty",
		Account:           testClaudeAccount(),
	}
	freshExhausted := &claudeQuotaSnapshot{
		CapturedAt:        now.Add(-1 * time.Minute),
		FiveHourRemaining: 0,
		FiveHourLimit:     10000,
		WeeklyRemaining:   50000,
		WeeklyLimit:       70000,
		Source:            "pty",
		Account:           testClaudeAccount(),
	}
	freshWeeklyZero := &claudeQuotaSnapshot{
		CapturedAt:        now.Add(-1 * time.Minute),
		FiveHourRemaining: 5000,
		FiveHourLimit:     10000,
		WeeklyRemaining:   0,
		WeeklyLimit:       70000,
		Source:            "pty",
		Account:           testClaudeAccount(),
	}
	freshExtraExhausted := &claudeQuotaSnapshot{
		CapturedAt:        now.Add(-1 * time.Minute),
		FiveHourRemaining: 5000,
		FiveHourLimit:     10000,
		WeeklyRemaining:   50000,
		WeeklyLimit:       70000,
		Windows: []harnesses.QuotaWindow{
			{Name: "Current session", LimitID: "session", UsedPercent: 10, State: "ok"},
			{Name: "Current week (all models)", LimitID: "weekly-all", UsedPercent: 42, State: "ok"},
			{Name: "Extra usage", LimitID: "extra", UsedPercent: 100, State: "exhausted"},
		},
		Source:  "pty",
		Account: testClaudeAccount(),
	}
	stale := &claudeQuotaSnapshot{
		CapturedAt:        now.Add(-20 * time.Minute),
		FiveHourRemaining: 5000,
		FiveHourLimit:     10000,
		WeeklyRemaining:   50000,
		WeeklyLimit:       70000,
		Source:            "pty",
	}
	freshMissingAccount := &claudeQuotaSnapshot{
		CapturedAt:        now.Add(-1 * time.Minute),
		FiveHourRemaining: 5000,
		FiveHourLimit:     10000,
		WeeklyRemaining:   50000,
		WeeklyLimit:       70000,
		Source:            "pty",
	}
	freshMissingSource := &claudeQuotaSnapshot{
		CapturedAt:        now.Add(-1 * time.Minute),
		FiveHourRemaining: 5000,
		FiveHourLimit:     10000,
		WeeklyRemaining:   50000,
		WeeklyLimit:       70000,
		Account:           testClaudeAccount(),
	}
	freshInvalidLimits := &claudeQuotaSnapshot{
		CapturedAt:        now.Add(-1 * time.Minute),
		FiveHourRemaining: 101,
		FiveHourLimit:     100,
		WeeklyRemaining:   50,
		WeeklyLimit:       100,
		Source:            "pty",
		Account:           testClaudeAccount(),
	}

	cases := []struct {
		name            string
		snapshot        *claudeQuotaSnapshot
		wantPref        harnesses.RoutingPreference
		wantState       harnesses.QuotaStateValue
		wantReasonSubst string
	}{
		{
			name:            "stale snapshot -> blocked/stale",
			snapshot:        stale,
			wantPref:        harnesses.RoutingPreferenceBlocked,
			wantState:       harnesses.QuotaStale,
			wantReasonSubst: "stale",
		},
		{
			name:            "fresh with headroom -> available/ok",
			snapshot:        fresh,
			wantPref:        harnesses.RoutingPreferenceAvailable,
			wantState:       harnesses.QuotaOK,
			wantReasonSubst: "",
		},
		{
			name:            "fresh but 5h exhausted -> blocked",
			snapshot:        freshExhausted,
			wantPref:        harnesses.RoutingPreferenceBlocked,
			wantState:       harnesses.QuotaBlocked,
			wantReasonSubst: "exhausted",
		},
		{
			name:            "fresh but weekly exhausted -> blocked",
			snapshot:        freshWeeklyZero,
			wantPref:        harnesses.RoutingPreferenceBlocked,
			wantState:       harnesses.QuotaBlocked,
			wantReasonSubst: "exhausted",
		},
		{
			name:            "fresh but extra usage exhausted -> blocked",
			snapshot:        freshExtraExhausted,
			wantPref:        harnesses.RoutingPreferenceBlocked,
			wantState:       harnesses.QuotaBlocked,
			wantReasonSubst: "extra",
		},
		{
			name:            "fresh but missing account -> blocked",
			snapshot:        freshMissingAccount,
			wantPref:        harnesses.RoutingPreferenceBlocked,
			wantState:       harnesses.QuotaBlocked,
			wantReasonSubst: "missing account",
		},
		{
			name:            "fresh but missing source -> blocked",
			snapshot:        freshMissingSource,
			wantPref:        harnesses.RoutingPreferenceBlocked,
			wantState:       harnesses.QuotaBlocked,
			wantReasonSubst: "missing source",
		},
		{
			name:            "fresh but impossible remaining -> blocked",
			snapshot:        freshInvalidLimits,
			wantPref:        harnesses.RoutingPreferenceBlocked,
			wantState:       harnesses.QuotaBlocked,
			wantReasonSubst: "invalid 5h remaining",
		},
	}

	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			freshFlag := isClaudeQuotaFresh(tc.snapshot, now, defaultClaudeQuotaStaleAfter)
			pref, state, reason := claudeQuotaRoutingFromSnapshot(tc.snapshot, freshFlag)
			assert.Equal(t, tc.wantPref, pref)
			assert.Equal(t, tc.wantState, state)
			if tc.wantReasonSubst != "" {
				assert.Contains(t, reason, tc.wantReasonSubst)
			}
		})
	}
}

