// TestClaudeQuotaRoutingViaQuotaStatus exercises the routing decision
// via the public QuotaStatus method (formerly ReadClaudeQuotaRoutingDecision).
func TestClaudeQuotaRoutingViaQuotaStatus(t *testing.T) {
	dir := t.TempDir()
	path := filepath.Join(dir, "claude-quota.json")
	t.Setenv(claudeQuotaCacheEnv, path)

	now := time.Date(2026, 4, 12, 12, 0, 0, 0, time.UTC)

	// No snapshot: QuotaUnavailable.
	r := &Runner{}
	status, err := r.QuotaStatus(context.Background(), now)
	require.NoError(t, err)
	assert.Equal(t, harnesses.QuotaUnavailable, status.State)
	assert.Equal(t, harnesses.RoutingPreferenceUnknown, status.RoutingPreference)

	// Write a fresh snapshot with headroom.
	require.NoError(t, writeClaudeQuota(path, claudeQuotaSnapshot{
		CapturedAt:        now.Add(-30 * time.Second),
		FiveHourRemaining: 9000,
		FiveHourLimit:     10000,
		WeeklyRemaining:   65000,
		WeeklyLimit:       70000,
		Source:            "pty",
		Account:           testClaudeAccount(),
	}))
	status, err = r.QuotaStatus(context.Background(), now)
	require.NoError(t, err)
	assert.Equal(t, harnesses.QuotaOK, status.State)
	assert.Equal(t, harnesses.RoutingPreferenceAvailable, status.RoutingPreference)
	assert.True(t, status.Fresh)
}

