131	// claudeQuotaSnapshotAge reports the age of a snapshot relative to now.
132	// A zero or future CapturedAt yields a zero age.
133	func claudeQuotaSnapshotAge(snapshot *claudeQuotaSnapshot, now time.Time) time.Duration {
134		if snapshot == nil || snapshot.CapturedAt.IsZero() {
135			return 0
136		}
137		age := now.UTC().Sub(snapshot.CapturedAt.UTC())
138		if age < 0 {
