144	// isClaudeQuotaFresh reports whether a snapshot exists and is newer than
145	// staleAfter relative to now. A nil snapshot is never fresh. A zero
146	// staleAfter falls back to defaultClaudeQuotaStaleAfter.
147	func isClaudeQuotaFresh(snapshot *claudeQuotaSnapshot, now time.Time, staleAfter time.Duration) bool {
148		if snapshot == nil || snapshot.CapturedAt.IsZero() {
149			return false
150		}
151		if staleAfter <= 0 {
152			staleAfter = defaultClaudeQuotaStaleAfter
153		}
154		return claudeQuotaSnapshotAge(snapshot, now) <= staleAfter
155	}
