157	// isClaudeQuotaExhaustedMessage recognizes Claude CLI quota failures that are
158	// emitted as plain text rather than structured quota data. Claude currently
159	// reports weekly exhaustion with wording like "out of extra usage", so callers
160	// must treat these strings as a hard quota signal.
161	func isClaudeQuotaExhaustedMessage(text string) bool {
162		normalized := strings.ToLower(strings.TrimSpace(text))
163		return strings.Contains(normalized, "out of extra usage") ||
164			strings.Contains(normalized, "usage limit reached") ||
165			strings.Contains(normalized, "quota exhausted") ||
166			strings.Contains(normalized, "weekly quota") ||
167			strings.Contains(normalized, "current week") && strings.Contains(normalized, "exhaust")
168	}
