185			CapturedAt:        now.UTC(),
186			FiveHourLimit:     100,
187			FiveHourRemaining: 0,
188			WeeklyLimit:       100,
189			WeeklyRemaining:   0,
190			Windows: []harnesses.QuotaWindow{
191				{Name: "Current week (all models)", LimitID: "weekly-all", WindowMinutes: 10080, UsedPercent: 100, State: "exhausted"},
192				{Name: "Extra usage", LimitID: "extra", UsedPercent: 100, State: "exhausted"},
193			},
194			Source:  "runtime_error",
195			Account: &harnesses.AccountInfo{PlanType: "unknown"},
196		}
197		_ = writeClaudeQuota(path, snap)
198		return true
