201	// validateClaudeQuotaSnapshotForRouting checks that a snapshot has the fields
202	// required for a trustworthy routing decision.
203	func validateClaudeQuotaSnapshotForRouting(snapshot *claudeQuotaSnapshot) error {
204		if snapshot == nil {
205			return fmt.Errorf("missing snapshot")
206		}
207		if strings.TrimSpace(snapshot.Source) == "" {
208			return fmt.Errorf("missing source")
209		}
210		if snapshot.Account == nil || strings.TrimSpace(snapshot.Account.PlanType) == "" {
211			return fmt.Errorf("missing account plan")
212		}
213		if snapshot.FiveHourLimit <= 0 {
214			return fmt.Errorf("invalid 5h limit")
215		}
216		if snapshot.WeeklyLimit <= 0 {
217			return fmt.Errorf("invalid weekly limit")
218		}
219		if snapshot.FiveHourRemaining < 0 || snapshot.FiveHourRemaining > snapshot.FiveHourLimit {
220			return fmt.Errorf("invalid 5h remaining")
221		}
222		if snapshot.WeeklyRemaining < 0 || snapshot.WeeklyRemaining > snapshot.WeeklyLimit {
223			return fmt.Errorf("invalid weekly remaining")
224		}
225		return nil
226	}
