228	func exhaustedClaudeQuotaWindow(windows []harnesses.QuotaWindow) string {
229		for _, window := range windows {
230			if !claudeQuotaWindowExhausted(window) {
231				continue
232			}
233			if strings.TrimSpace(window.LimitID) != "" {
234				return window.LimitID
235			}
236			if strings.TrimSpace(window.Name) != "" {
237				return window.Name
238			}
239			return "unknown"
240		}
241		return ""
242	}
