335	func writeServiceUsageSession(t *testing.T, logDir, sessionID string, startAt time.Time, start sessionlog.SessionStartData, end sessionlog.SessionEndData) {
336		t.Helper()
337		logger := sessionlog.NewLogger(logDir, sessionID)
338		startEvent := sessionlog.NewEvent(sessionID, 0, agentcore.EventSessionStart, start)
339		startEvent.Timestamp = startAt
340		logger.Write(startEvent)
341		endEvent := sessionlog.NewEvent(sessionID, 1, agentcore.EventSessionEnd, end)
342		endEvent.Timestamp = startAt.Add(time.Second)
343		logger.Write(endEvent)
344		if err := logger.Close(); err != nil {
345			t.Fatal(err)
346		}
347	}
