44	// fakeCodexQuotaHarness is a minimal harnesses.QuotaHarness for tests that
45	// need to observe or control codex quota refresh calls without invoking the
46	// real codex CLI. QuotaStatus always returns QuotaUnavailable so that
47	// primaryQuotaCacheStatus sees the cache as missing and requests a refresh;
48	// RefreshQuota invokes refreshFn (if set) or returns a fresh-available status.
49	type fakeCodexQuotaHarness struct {
50		refreshFn    func(ctx context.Context) (harnesses.QuotaStatus, error)
51		refreshCalls atomic.Int32
52	}
53	
54	func newFakeCodexQuotaHarness() *fakeCodexQuotaHarness {
55		return &fakeCodexQuotaHarness{}
56	}
57	
58	func (f *fakeCodexQuotaHarness) Info() harnesses.HarnessInfo {
59		return harnesses.HarnessInfo{Name: "codex", Type: "subprocess"}
60	}
61	func (f *fakeCodexQuotaHarness) HealthCheck(_ context.Context) error { return nil }
62	func (f *fakeCodexQuotaHarness) Execute(_ context.Context, _ harnesses.ExecuteRequest) (<-chan harnesses.Event, error) {
63		panic("fakeCodexQuotaHarness: Execute not supported")
64	}
65	func (f *fakeCodexQuotaHarness) QuotaStatus(_ context.Context, _ time.Time) (harnesses.QuotaStatus, error) {
66		return harnesses.QuotaStatus{State: harnesses.QuotaUnavailable}, nil
67	}
68	func (f *fakeCodexQuotaHarness) RefreshQuota(ctx context.Context) (harnesses.QuotaStatus, error) {
69		f.refreshCalls.Add(1)
70		if f.refreshFn != nil {
71			return f.refreshFn(ctx)
72		}
73		return harnesses.QuotaStatus{
74			Fresh:             true,
75			State:             harnesses.QuotaOK,
76			RoutingPreference: harnesses.RoutingPreferenceAvailable,
77		}, nil
78	}
