569	// TestHealthCheck_ClaudeSkipsRefreshWhenFresh verifies that HealthCheck does
570	// NOT invoke the PTY quota refresher when the cached snapshot is younger than
571	// default quota refresh debounce (15m).
572	func TestHealthCheck_ClaudeSkipsRefreshWhenFresh(t *testing.T) {
573		dir := t.TempDir()
574		cachePath := filepath.Join(dir, "claude-quota.json")
575		t.Setenv("FIZEAU_CLAUDE_QUOTA_CACHE", cachePath)
576	
577		// Write a snapshot that is only 30s old (fresh).
578		freshSnap := claudeharness.ClaudeQuotaSnapshot{
579			CapturedAt:        time.Now().UTC().Add(-30 * time.Second),
580			FiveHourRemaining: 80,
581			FiveHourLimit:     100,
582			WeeklyRemaining:   90,
583			WeeklyLimit:       100,
584			Source:            "pty",
585			Account:           &harnesses.AccountInfo{PlanType: "Claude Max"},
586		}
587		if err := claudeharness.WriteClaudeQuota(cachePath, freshSnap); err != nil {
588			t.Fatalf("setup: WriteClaudeQuota: %v", err)
589		}
590	
591		// Inject a fake refresher that must NOT be called.
592		refreshCalled := false
593		setClaudeQuotaRefresherForTest(t, func(timeout time.Duration) ([]harnesses.QuotaWindow, *harnesses.AccountInfo, error) {
594			refreshCalled = true
595			return nil, nil, nil
596		})
597	
598		svc := newTestService(t, ServiceOptions{})
599		svc.healthCheckRefreshClaudeQuota(context.Background())
600	
601		if refreshCalled {
602			t.Error("expected healthCheckClaudeQuotaRefresher NOT to be called for fresh cache")
603		}
604	
605		// Verify the cache timestamp is unchanged (still matches freshSnap).
606		loaded, ok := claudeharness.ReadClaudeQuotaFrom(cachePath)
607		if !ok {
608			t.Fatal("expected cache file to still exist")
609		}
610		if !loaded.CapturedAt.Equal(freshSnap.CapturedAt) {
611			t.Errorf("cache was unexpectedly rewritten: got CapturedAt %v, want %v",
612				loaded.CapturedAt, freshSnap.CapturedAt)
613		}
614	}
