887	func resetPrimaryQuotaRefreshForTest(t *testing.T) {
888		t.Helper()
889		primaryQuotaRefresh.mu.Lock()
890		oldLast := primaryQuotaRefresh.lastAttempt
891		oldInFlight := primaryQuotaRefresh.inFlight
892		primaryQuotaRefresh.lastAttempt = make(map[string]time.Time)
893		primaryQuotaRefresh.inFlight = make(map[string]bool)
894		primaryQuotaRefresh.mu.Unlock()
895		t.Cleanup(func() {
896			primaryQuotaRefresh.mu.Lock()
897			primaryQuotaRefresh.lastAttempt = oldLast
898			primaryQuotaRefresh.inFlight = oldInFlight
899			primaryQuotaRefresh.mu.Unlock()
900		})
