911	func waitForQuotaRefreshes(t *testing.T, done <-chan string, want ...string) {
912		t.Helper()
913		seen := map[string]bool{}
914		deadline := time.After(time.Second)
915		for len(seen) < len(want) {
916			select {
917			case name := <-done:
918				seen[name] = true
919			case <-deadline:
920				t.Fatalf("timed out waiting for quota refreshes; saw %v want %v", seen, want)
921			}
922		}
923		for _, name := range want {
924			if !seen[name] {
925				t.Fatalf("missing quota refresh %q; saw %v", name, seen)
926			}
927		}
928	}
929	
930	func waitForQuotaRefreshFiles(t *testing.T, paths ...string) {
931		t.Helper()
932		deadline := time.After(time.Second)
933		for {
934			allPresent := true
935			for _, path := range paths {
936				if _, err := os.Stat(path); err != nil {
937					allPresent = false
938					break
939				}
940			}
941			if allPresent {
942				return
943			}
944			select {
945			case <-deadline:
946				t.Fatalf("timed out waiting for quota refresh files: %v", paths)
947			default:
948				time.Sleep(time.Millisecond)
949			}
950		}
951	}
