427	func harnessGoldenRecordHarnesses() []string {
428		raw := strings.TrimSpace(os.Getenv("FIZEAU_HARNESS_RECORD_HARNESSES"))
429		if raw == "" {
430			return []string{"claude", "codex"}
431		}
432		parts := strings.Split(raw, ",")
433		harnesses := make([]string, 0, len(parts))
434		for _, part := range parts {
435			if harness := strings.TrimSpace(part); harness != "" {
436				harnesses = append(harnesses, harness)
437			}
438		}
439		if len(harnesses) == 0 {
440			return []string{"claude", "codex"}
441		}
442		return harnesses
443	}
