459	func drainRawExecute(ctx context.Context, events <-chan ServiceEvent) ([]ServiceEvent, *DrainExecuteResult, error) {
460		result := &DrainExecuteResult{}
461		var raw []ServiceEvent
462		for {
463			select {
464			case <-ctx.Done():
465				return raw, result, ctx.Err()
466			case ev, ok := <-events:
467				if !ok {
468					if result.Final == nil {
469						return raw, result, context.Canceled
470					}
471					return raw, result, nil
472				}
473				raw = append(raw, ev)
474				decoded, err := DecodeServiceEvent(ev)
475				if err != nil {
476					return raw, result, err
477				}
478				result.append(decoded)
479			}
480		}
481	}
