199		now := time.Now()
200		switch harnessName {
201		case "claude":
202			qh, ok := s.harnessByName("claude").(harnesses.QuotaHarness)
203			if !ok {
204				return quotaCacheStatus{}
205			}
206			status, err := qh.QuotaStatus(ctx, now)
207			if err != nil {
208				return quotaCacheStatus{}
209			}
210			if status.State == harnesses.QuotaUnavailable {
211				return quotaCacheStatus{needsRefresh: true}
212			}
213			stale := !status.CapturedAt.IsZero() && now.Sub(status.CapturedAt) >= debounce
214			return quotaCacheStatus{
215				needsRefresh: stale,
216				usable:       !stale,
217			}
218		case "codex":
219			qh, ok := s.harnessByName("codex").(harnesses.QuotaHarness)
220			if !ok {
221				return quotaCacheStatus{}
222			}
223			status, err := qh.QuotaStatus(ctx, now)
224			if err != nil {
225				return quotaCacheStatus{}
226			}
227			if status.State == harnesses.QuotaUnavailable {
228				return quotaCacheStatus{needsRefresh: true}
229			}
230			usable := status.Fresh && status.RoutingPreference == harnesses.RoutingPreferenceAvailable
231			return quotaCacheStatus{
232				needsRefresh: !usable,
233				usable:       usable,
234			}
235		default:
236			return quotaCacheStatus{}
237		}
